code = """import json
import re

# Read latest packages (one per package name)
with open('/tmp/latest_npm_packages.json', 'r') as f:
    latest_packages = json.load(f)

print("Latest packages count: " + str(len(latest_packages)))

# Read project mappings with stars
proj_result = locals()['var_functions.query_db:82']
if isinstance(proj_result, str) and proj_result.endswith('.json'):
    with open(proj_result, 'r') as f:
        all_mappings = json.load(f)
else:
    all_mappings = proj_result

print("All mappings count: " + str(len(all_mappings)))

# Extract stars from all mappings and create lookup
# Key is (Name, Version) -> Star count
star_lookup = {}
for mapping in all_mappings:
    info_text = mapping.get('Project_Information', '')
    star_match = re.search(r'(\d+)\s+stars', info_text)
    if star_match:
        stars = int(star_match.group(1))
        key = (mapping['Name'], mapping['Version'])
        star_lookup[key] = stars

print("Star lookup entries: " + str(len(star_lookup)))

# Match latest packages with their star counts
matched = []
for pkg in latest_packages:
    key = (pkg['Name'], pkg['Version'])
    if key in star_lookup:
        matched.append({
            'Name': pkg['Name'],
            'Version': pkg['Version'],
            'Stars': star_lookup[key]
        })

print("Matched packages: " + str(len(matched)))

# Sort by stars in descending order
top_packages = sorted(matched, key=lambda x: x['Stars'], reverse=True)[:5]

print("\nTOP 5 NPM PACKAGES (latest version) BY GITHUB STARS:")
for i, pkg in enumerate(top_packages, 1):
    print(str(i) + ". " + pkg['Name'] + " (v" + pkg['Version'] + ") - " + str(pkg['Stars']) + " stars")

# Also, let's check if we need to improve the match
if len(top_packages) < 5:
    print("Warning: Found fewer than 5 matches")

print("__RESULT__:")
print(json.dumps(top_packages))"""

